  current: {
    open: jest.fn(),
    close: jest.fn(),
  },
};

it('should render correctly', () => {
  const { getByText } = render(
    <TestProvider>
      <PointsInfoBottomSheet modalizeRef={mockModalizeRef} />
    </TestProvider>,
  );
  // Tests work because the actual design-system components render
});
```

### 7. Modalize Mock Details (from setup.js)
Lines 73-88 show the key mock:
```javascript
jest.mock(
  'react-native-modalize',
  () => {
    const React = require('react');
    const { View } = require('react-native');
    const Modalize = React.forwardRef(({ children }, ref) => {
      React.useImperativeHandle(ref, () => ({
        open: jest.fn(),
        close: jest.fn(),
      }));
      return React.createElement(View, { testID: 'modalize' }, children);
    });
    return { Modalize };
  },
  { virtual: true },
);
```

### 8. TypeScript Path Configuration
**tsconfig.json** paths:
```json
"paths": {
  "~/store": ["./@types/store.d.ts"]
}
```
Only the store alias is mapped; @semparar imports resolve normally.

### Key Insights
1. **No explicit BackDropBottom mock** - The component and its children (Button, Text, Box) are used directly from @semparar/design-system-app
2. **Modalize is mocked at the react-native-modalize level** - This is sufficient because BackDropBottom wraps Modalize internally
3. **Theme is imported directly** - Tests use real theme from design-system
4. **Virtual mocks enabled** - Many setup.js mocks use `{ virtual: true }` for packages that may not be installed or to override resolution
5. **No moduleNameMapper overrides** - Design system is consumed as-is, which means tests get actual component implementations (beneficial for integration-style testing)
